def solve(nums, target):
    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1

# Additional checks for pitfalls
def verify_pitfalls(nums, target):
    if not nums:
        return -1, -1  # Handle no-solution case
    if len(nums) != len(set(nums)):
        raise ValueError("Indices are reused in the input list.")

# Example usage
def main(nums, target):
    verify_pitfalls(nums, target)
    return solve(nums, target)
